const rows = $input.all().map(item => item.json);

if (rows.length === 0) {
  throw new Error('No rows received from Supabase.');
}

const commentsArray = rows
  .map(row => row.counter_reply_text)
  .filter(comment => comment !== null && comment !== undefined)
  .map(comment => String(comment).trim())
  .filter(comment => comment.length > 0);

if (commentsArray.length < 10) {
  throw new Error(`Service 8404 requires at least 10 comments. You provided ${commentsArray.length}.`);
}

if (commentsArray.length > 250) {
  throw new Error(`Service 8404 allows a maximum of 250 comments. You provided ${commentsArray.length}.`);
}

const formattedComments = commentsArray.join('\n');

return [
  {
    json: {
      post_id: String(rows[0].post_id),
      comments: formattedComments,
      commentCount: commentsArray.length
    }
  }
];

// n8n Code node
// Input expected in: $('Code in JavaScript2').first().json.comments
// Output: multiple items, one per 3000-character chunk

const maxLength = 3000;
const comments = $('Code in JavaScript2').first().json.comments || "";

let text = "";

// If comments is an array, number each comment and add an empty line between them
if (Array.isArray(comments)) {
  text = comments
    .map((comment, index) => `${index + 1}. ${String(comment).trim()}`)
    .join("\n\n");
} else {
  // If comments is already a string, number each line/comment and add an empty line between them
  text = comments
    .split("\n")
    .map(comment => comment.trim())
    .filter(comment => comment !== "")
    .map((comment, index) => `${index + 1}. ${comment}`)
    .join("\n\n");
}

const chunks = [];

for (let i = 0; i < text.length; i += maxLength) {
  chunks.push({
    json: {
      message: text.slice(i, i + maxLength),
      chunkIndex: chunks.length + 1,
    },
  });
}

return chunks;

const route = $('Parse Telegram Message').first().json;
const promptRequired = route.likes_prompt_required === true;
const tokens = String(route.command_args || '').trim().split(/\s+/).filter(Boolean);
const postId = String(route.post_id || '').trim();
const rawAmount = promptRequired ? $json?.data?.Amount : route.like_amount;
const amountText = String(rawAmount ?? '').trim();

let errorMessage = '';
if (!/^[0-9]{1,19}$/.test(postId)) {
  errorMessage = 'Usage: /order_likes POST_ID AMOUNT. POST_ID must be 1 to 19 digits.';
} else if (!promptRequired && tokens.length !== 2) {
  errorMessage = 'Usage: /order_likes POST_ID AMOUNT. Provide exactly a post ID and a positive whole-number amount.';
} else if (!/^\d+$/.test(amountText) || !/[1-9]/.test(amountText)) {
  errorMessage = 'Like amount must be a positive whole number.';
}

const normalizedAmount = errorMessage ? '' : amountText.replace(/^0+(?=\d)/, '');

return [{
  json: {
    ...route,
    post_id: postId,
    like_amount: normalizedAmount,
    likes_input_valid: !errorMessage,
    error_message: errorMessage,
  },
}];

const input = $input.first()?.json || $json || {};
const message = input.message || {};
const callbackQuery = input.callback_query || null;
const callbackData = String(callbackQuery?.data || '');
const text = callbackData || String(message.text || '').trim();
const chatId = String(callbackQuery?.message?.chat?.id || callbackQuery?.from?.id || message.chat?.id || '');
const lower = text.toLowerCase();

let intent = 'UNKNOWN';
let post_id = '';
let command = '';
let command_args = '';
let like_amount = '';
let likes_prompt_required = false;
const callback_query_id = callbackQuery?.id || '';
const input_source = callbackQuery ? 'callback' : 'command';

const callbackMatch = callbackData.match(/^(hide_replies|ignore|snooze|resume|order_likes):([0-9]{1,19})$/);
if (callbackMatch) {
  const callbackCommand = callbackMatch[1];
  post_id = callbackMatch[2];
  command = callbackCommand;
  command_args = post_id;

  if (callbackCommand === 'hide_replies') intent = 'HIDE_REPLIES';
  if (callbackCommand === 'ignore') intent = 'IGNORE_POST';
  if (callbackCommand === 'snooze') intent = 'SNOOZE_POST';
  if (callbackCommand === 'resume') intent = 'RESUME_POST';
  if (callbackCommand === 'order_likes') {
    intent = 'ORDER_LIKES';
    like_amount = null;
    likes_prompt_required = true;
  }
}

const commandMatch = !callbackMatch ? text.match(/^\/(\w+)(?:@\w+)?(?:\s+([\s\S]*))?$/) : null;

function setPostIntent(nextIntent, commandName, args) {
  intent = nextIntent;
  command = commandName;
  const idMatch = String(args || '').match(/([0-9]{1,19})/);
  post_id = idMatch ? idMatch[1] : '';
}

function setLikesIntent(commandName, args) {
  intent = 'ORDER_LIKES';
  command = commandName;
  const tokens = String(args || '').trim().split(/\s+/).filter(Boolean);
  post_id = /^[0-9]{1,19}$/.test(tokens[0] || '') ? tokens[0] : '';
  like_amount = tokens.length >= 2 ? tokens[1] : '';
  likes_prompt_required = Boolean(callbackQuery && post_id && tokens.length === 1);
  if (likes_prompt_required) like_amount = null;
}

function applyCompatibilityParsing() {
  if (lower === 'help' || lower === 'start') {
    intent = 'HELP';
    return;
  }

  const hideMatch = text.match(/hide\s+(?:the\s+)?replies\s+(?:of|for)\s+post\s*:?\s*([0-9]{1,19})/i)
