// n8n Code node
// Input expected in: $('Code in JavaScript2').first().json.comments
// Output: multiple items, one per 3000-character chunk

const maxLength = 3000;
const comments = $('Code in JavaScript2').first().json.comments || "";

let text = "";

// If comments is an array, number each comment and add an empty line between them
if (Array.isArray(comments)) {
  text = comments
    .map((comment, index) => `${index + 1}. ${String(comment).trim()}`)
    .join("\n\n");
} else {
  // If comments is already a string, number each line/comment and add an empty line between them
  text = comments
    .split("\n")
    .map(comment => comment.trim())
    .filter(comment => comment !== "")
    .map((comment, index) => `${index + 1}. ${comment}`)
    .join("\n\n");
}

const chunks = [];

for (let i = 0; i < text.length; i += maxLength) {
  chunks.push({
    json: {
      message: text.slice(i, i + maxLength),
      chunkIndex: chunks.length + 1,
    },
  });
}

return chunks;

